//vip.opstream11.com/20221012/36678_2200df45/index.m3u8"}]}],"time":"72 phút","description":"<p>Ray - một thiếu niên luôn sống với thái độ sống bất cần, là con tốt trong vụ li hôn triệu Đô của mẹ cậu, một nữ diễn viên quen với lối sống xa hoa phù phiếm, nhưng hiện nó đang bị đe dọa và phụ thuộc tất cả vào quyết định của Ray. Kế hoạch của người mẹ mưu mô bị đảo lộn khi sự xuất hiện của cô gái giữ trẻ mới được thuê chiếm được tình cảm của Ray. Một âm mưu khác ngầm được tiến hành. Đâu là cái kết cho người mẹ và đôi tình nhân trẻ???</p>","tmdb":{"type":"movie","id":"324254","season":null,"vote_average":5.9,"vote_count":15},"modified":"2022-10-26T12:08:36.000Z"},{"id":"6358c142a96d5b232ec3a83b","_id":"6358c142a96d5b232ec3a83b","title":"Nhân Tố Nguy Hiểm","origin_name":"The Danger Element","slug":"nhan-to-nguy-hiem","year":2017,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2282e0fc277084dfd435","name":"Viễn Tưởng","slug":"vien-tuong"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Nhân Tố Nguy Hiểm","link_embed":"https://vip.opstream11.com/share/3fcd8a68679d59ebe1b2939ff9556b6f","link_m3u8":"https://vip.opstream11.com/20221012/36679_8ae6afa8/index.m3u8"}]}],"time":"100 Phút","description":"<p>Raiders of the Lost Ark gặp Batman trong cuộc phiêu lưu võ thuật đầy hành động này.</p>","tmdb":{"type":"movie","id":"476020","season":null,"vote_average":6,"vote_count":3},"modified":"2022-10-26T12:10:26.000Z"},{"id":"6358c190a96d5b232ec3aa7f","_id":"6358c190a96d5b232ec3aa7f","title":"Những Cái Chết Được Báo Trước","origin_name":"The Before Time","slug":"nhung-cai-chet-duoc-bao-truoc","year":2014,"type":"single","genr